#include <iostream>
#include <string>
#include <sstream>
#include <functional>

void run_grading_logic();

std::string execute_and_capture(const std::string& input_str) {
    std::stringstream ss_in(input_str);
    std::stringstream ss_out;

    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();

    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());

    try {
        run_grading_logic();
    } catch (const std::exception& e) {
        ss_out << "Error: " << e.what() << std::endl;
    }

    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    std::string output = ss_out.str();
    size_t pos = output.find("Enter student's score (0-100): ");
    if (pos != std::string::npos) {
        output.erase(pos, std::string("Enter student's score (0-100): ").length());
    }
    size_t first = output.find_first_not_of(" \n\r\t");
    size_t last = output.find_last_not_of(" \n\r\t");
    if (std::string::npos == first || std::string::npos == last) {
        return "";
    }
    return output.substr(first, (last - first + 1));
}

int main() {
    return 0;
}
